body { font-family: sans-serif; background: #0f172a; color: #fff; padding: 20px; margin: 0; }
        .container { max-width: 900px; margin: 0 auto; background: #1e293b; padding: 25px; border-radius: 12px; box-shadow: 0 10px 15px rgba(0,0,0,0.3); }
        h2 { color: #38bdf8; text-align: center; margin-top: 0; }
        label { font-weight: bold; color: #94a3b8; display: block; margin-top: 15px; margin-bottom: 5px; }
        input, textarea { width: 100%; padding: 12px; background: #334155; border: 1px solid #475569; border-radius: 6px; color: #fff; box-sizing: border-box; font-size: 15px; }
        textarea { font-family: monospace; height: 320px; resize: vertical; }
        button { width: 100%; padding: 14px; background: #38bdf8; color: #0f172a; font-weight: bold; border: none; border-radius: 6px; cursor: pointer; font-size: 16px; margin-top: 20px; transition: 0.2s; }
        button:hover { background: #0ea5e9; }
        .preview { margin-top: 20px; background: #000; padding: 15px; border-radius: 6px; overflow-x: auto; display: none; }
        pre { margin: 0; color: #4af2a1; font-family: monospace; white-space: pre-wrap; }

pro_dashboard.script:
function proExtractAndDownload() {
    const screenName = document.getElementById('screenName').value.trim();
    const rawCode = document.getElementById('fullCodeInput').value;

    if (!screenName || !rawCode.trim()) {
        alert("Kripya saari details bharein!");
        return;
    }

    const parser = new DOMParser();
    const doc = parser.parseFromString(rawCode, 'text/html');

    // 1. External Script Sources (src wale) aur Custom JavaScript dono ko alag karna
    const scriptElements = doc.querySelectorAll('script');
    let externalScripts = [];
    let customScriptText = "";

    scriptElements.forEach(script => {
        if (script.hasAttribute('src')) {
            externalScripts.push(script.getAttribute('src'));
        } else {
            customScriptText += script.textContent + "\n";
        }
        script.remove();
    });

    // 2. Custom CSS (<style>) aur External CSS Links dono ko manage karna
    const styleElements = doc.querySelectorAll('style');
    let customCssText = "";
    styleElements.forEach(style => {
        customCssText += style.textContent + "\n";
        style.remove();
    });

    const linkElements = doc.querySelectorAll('link[rel="stylesheet"]');
    let externalCss = [];
    linkElements.forEach(link => {
        externalCss.push(link.getAttribute('href'));
        link.remove();
    });

    // 3. Head Quality & Metadata (Meta tags, Title) ki settings
    let metaTagsHtml = "";
    const metaElements = doc.querySelectorAll('meta');
    metaElements.forEach(meta => {
        metaTagsHtml += meta.outerHTML + "\n";
        meta.remove();
    });

    const titleEl = doc.querySelector('title');
    let pageTitle = titleEl ? titleEl.innerText : "Cloud App Window";

    // 4. Bacha Hua Clean HTML Body Content
    const bodyContent = doc.body ? doc.body.innerHTML.trim() : doc.documentElement.innerHTML.trim();

    // Advanced Production JSON Blueprint Setup
    const jsonStructure = {
        "page_settings": {
            "initial_screen": screenName,
            "meta_tags": metaTagsHtml.trim(),
            "title": pageTitle,
            "external_css": externalCss,
            "external_scripts": externalScripts,
            "custom_css": customCssText.trim()
        },
        "screens": {}
    };

    jsonStructure.screens[screenName] = {
        "html": bodyContent,
        "script": customScriptText.trim()
    };

    const finalJsonString = JSON.stringify(jsonStructure, null, 2);

    document.getElementById('jsonOutput').textContent = finalJsonString;
    document.getElementById('previewBox').style.display = "block";

    const blob = new Blob([finalJsonString], { type: "application/json" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "ui-config.json";
    link.click();
}
